import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Stack;
import java.util.StringTokenizer;

public class BOJ_12100 {
	static int[][] map;
	static int N;
	static int maxBlock;
	
	public static void main(String[] args) throws IOException {
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		
		N = Integer.parseInt(br.readLine());
		map = new int[N][N];
		
		for (int i = 0; i < N; i++) {
			StringTokenizer st = new StringTokenizer(br.readLine());
			for (int j = 0; j < N; j++) {
				map[i][j] = Integer.parseInt(st.nextToken());
			}
		}
		
		dfs(0, map);
		System.out.println(maxBlock);
		
	}
	
	public static int[][] rotateCW(int[][] mat) {
	    int[][] tmp = new int[N][N];
	    for (int i = 0; i < N; i++) {
	        for (int j = 0; j < N; j++) {
	            tmp[i][j] = mat[j][N - 1 - i];
	        }
	    }
	    return tmp;
	}
	
	public static void dfs(int moveCnt, int[][] mat) {
		if (moveCnt == 5) {
			int tmpMax = 0;
			for (int i = 0; i < N; i++) {
				for (int j = 0; j < N; j++) {
					tmpMax = Math.max(tmpMax, mat[i][j]);
				}
			}
			maxBlock = Math.max(tmpMax, maxBlock);
			return;
		}
		
		for (int i = 0; i < 4; i++) {
			mat = rotateCW(mat);
			int[][] next = action(mat);
			dfs(moveCnt+1, next);
		}
	}
	
	public static int[][] action(int[][] mat) {
		int[][] result = new int[N][N];
		
		for (int i = 0; i < N; i++) {
			Stack<Integer> s = new Stack<>();
			int nCnt = 0;
			boolean isCollapsable = true;
			
			for (int j = 0; j < N; j++) {
				if (mat[i][j] != 0) {
					s.push(mat[i][j]);
					nCnt++;
				}
			}
			
			if (nCnt > 0) {
				int ref = s.pop();
				int posIdx = N-1;
				result[i][posIdx] = ref;
				
				while (!s.isEmpty()) {
					int toAdd = s.pop();
					if (ref == toAdd && isCollapsable) {
						result[i][posIdx] += toAdd;
						isCollapsable = false;
						ref = -1;
					} else {
						posIdx--;
						result[i][posIdx] = toAdd;
						isCollapsable = true;
						ref = toAdd;
					}                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
				}
			}
		}
		return result;
	}

}
